#include<bits/stdc++.h>
using namespace std;
long long dp[1001][1001],up[1001][1001],n,m,a[1001][1001],down[1001][1001];
int main()
{
    scanf("%lld%lld",&n,&m);
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m;j++)
        {
            scanf("%lld",&a[i][j]);
        }
    }
    memset(dp,0x8f,sizeof(dp));
    memset(up,0x8f,sizeof(up));
    memset(down,0x8f,sizeof(down));
    up[0][1]=0;
    for(int i=1;i<=n;i++)
    {
        dp[i][1]=up[i][1]=up[i-1][1]+a[i][1];
    }
    for(int j=2;j<=m;j++)
    {
        up[1][j]=dp[1][j-1]+a[1][j];
        for(int i=2;i<=n;i++)
        {
            up[i][j]=max(dp[i][j-1],up[i-1][j])+a[i][j];
            dp[i][j]=up[i][j];
        }
        down[n][j]=dp[n][j-1]+a[n][j];
        for(int i=n-1;i>=1;i--)
        {
            down[i][j]=max(dp[i][j-1],down[i+1][j])+a[i][j];
            dp[i][j]=max(dp[i][j],down[i][j]);
        }
    }
    printf("%lld",dp[n][m]);
    return 0;
}
